package com.hospital.management.controller.prescription;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.PrescriptionServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;@WebServlet("/prescriptions")public class PrescriptionListServlet extends HttpServlet {private final PrescriptionService service;public PrescriptionListServlet(){this(new PrescriptionServiceImpl());}public PrescriptionListServlet(PrescriptionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{int p=Math.max(1,PrescriptionRequest.number(q.getParameter("page"),1)),z=Math.min(100,Math.max(1,PrescriptionRequest.number(q.getParameter("size"),10)));q.setAttribute("prescriptionPage",service.listPrescriptions(new PageRequest(p,z,q.getParameter("search")),PrescriptionRequest.id(q.getParameter("patientId")),PrescriptionRequest.id(q.getParameter("doctorId")),PrescriptionRequest.id(q.getParameter("departmentId")),PrescriptionRequest.date(q.getParameter("dateFrom")),PrescriptionRequest.date(q.getParameter("dateTo")),q.getParameter("status"),PrescriptionRequest.user(q)));q.getRequestDispatcher("/WEB-INF/views/prescriptions/list.jsp").forward(q,r);}}
